# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System;
using System.Collections.Generic;

[System.Serializable]
public class PlayerStats
{
    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 0;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float baseAttack = 10f;
    public float baseDefense = 5f;
    public float criticalChance = 0.1f;
    public float criticalMultiplier = 2.0f;
}

[System.Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public string description;
    public int basePrice;
    public int currentPrice;
    public ItemType itemType;
    public float statBonus;
    public bool isPremium;
    public int premiumCost;
}

public enum ItemType
{
    HealthPotion,
    AttackBoost,
    DefenseBoost,
    CritBoost,
    PremiumWeapon,
    PremiumArmor
}

public class GameManager : MonoBehaviour
{
    public static GameManager Instance;

    public PlayerStats playerStats = new PlayerStats();
    public List<ShopItem> shopInventory = new List<ShopItem>();
    public List<ShopItem> purchasedItems = new List<ShopItem>();

    public float damageReductionPerDefense = 0.5f;
    public float levelScalingFactor = 1.1f;
    public float discountPercentage = 0f;

    public event Action<float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnPremiumCurrencyChanged;
    public event Action OnPlayerDied;
    public event Action<ShopItem> OnItemPurchased;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }

        InitializeShop();
        LoadPlayerData();
    }

    private void InitializeShop()
    {
        shopInventory.Clear();

        shopInventory.Add(new ShopItem
        {
            itemId = "health_potion_small",
            itemName = "Small Health Potion",
            description = "Restores 25 HP",
            basePrice = 50,
            currentPrice = 50,
            itemType = ItemType.HealthPotion,
            statBonus = 25f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "health_potion_large",
            itemName = "Large Health Potion",
            description = "Restores 75 HP",
            basePrice = 120,
            currentPrice = 120,
            itemType = ItemType.HealthPotion,
            statBonus = 75f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "attack_boost",
            itemName = "Attack Boost",
            description = "Increases attack by 5",
            basePrice = 200,
            currentPrice = 200,
            itemType = ItemType.AttackBoost,
            statBonus = 5f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "defense_boost",
            itemName = "Defense Boost",
            description = "Increases defense by 3",
            basePrice = 180,
            currentPrice = 180,
            itemType = ItemType.DefenseBoost,
            statBonus = 3f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "crit_boost",
            itemName = "Critical Chance Boost",
            description = "Increases crit chance by 5%",
            basePrice = 300,
            currentPrice = 300,
            itemType = ItemType.CritBoost,
            statBonus = 0.05f,
            isPremium = false
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "premium_sword",
            itemName = "Legendary Sword",
            description = "Increases attack by 25",
            basePrice = 0,
            currentPrice = 0,
            itemType = ItemType.PremiumWeapon,
            statBonus = 25f,
            isPremium = true,
            premiumCost = 100
        });

        shopInventory.Add(new ShopItem
        {
            itemId = "premium_armor",
            itemName = "Legendary Armor",
            description = "Increases defense by 15 and max HP by 50",
            basePrice = 0,
            currentPrice = 0,
            itemType = ItemType.PremiumArmor,
            statBonus = 15f,
            isPremium = true,
            premiumCost = 150
        });

        RecalculateShopPrices();
    }

    public void RecalculateShopPrices()
    {
        foreach (var item in shopInventory)
        {
            if (!item.isPremium)
            {
                float levelMultiplier = Mathf.Pow(levelScalingFactor, playerStats.playerLevel - 1);
                float discountMultiplier = 1f - (discountPercentage / 100f);
                item.currentPrice = Mathf.RoundToInt(item.basePrice * levelMultiplier * discountMultiplier);
                item.currentPrice = Mathf.Max(item.currentPrice, 1);
            }
        }
    }

    // --- Damage System ---

    public float CalculateOutgoingDamage(float enemyDefense)
    {
        float rawDamage = playerStats.baseAttack * Mathf.Pow(levelScalingFactor, playerStats.playerLevel - 1);

        bool isCritical = UnityEngine.Random.value <= playerStats.criticalChance;
        if (isCritical)
        {
            rawDamage *= playerStats.criticalMultiplier;
            Debug.Log("Critical Hit!");
        }

        float damageReduction = enemyDefense * damageReductionPerDefense;
        float finalDamage = Mathf.Max(rawDamage - damageReduction, 1f);

        return finalDamage;
    }

    public float CalculateIncomingDamage(float rawDamage)
    {
        float damageReduction = playerStats.baseDefense * damageReductionPerDefense;
        float finalDamage = Mathf.Max(rawDamage - damageReduction, 1f);
        return finalDamage;
    }

    public void TakeDamage(float rawDamage)
    {
        float finalDamage = CalculateIncomingDamage(rawDamage);
        playerStats.currentHealth -= finalDamage;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, playerStats.maxHealth);

        Debug.Log($"Player took {finalDamage} damage. Health: {playerStats.currentHealth}/{playerStats.maxHealth}");

        OnHealthChanged?.Invoke(playerStats.currentHealth);

        if (playerStats.currentHealth <= 0f)
        {
            HandlePlayerDeath();
        }

        SavePlayerData();
    }

    public void Heal(float amount)
    {
        playerStats.currentHealth += amount;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, playerStats.maxHealth);

        Debug.Log($"Player healed {amount} HP. Health: {playerStats.currentHealth}/{playerStats.maxHealth}");

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    private void HandlePlayerDeath()
    {
        Debug.Log("Player has died!");
        OnPlayerDied?.Invoke();
    }

    public void Respawn()
    {
        playerStats.currentHealth = playerStats.maxHealth;
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    // --- Currency System ---

    public void AddCurrency(int amount)
    {
        playerStats.currency += amount;
        Debug.Log($"Gained {amount} currency. Total: {playerStats.currency}");
        OnCurrencyChanged?.Invoke(playerStats.currency);
        SavePlayerData();
    }

    public bool SpendCurrency(int amount)
    {
        if (playerStats.currency >= amount)
        {
            playerStats.currency -= amount;
            Debug.Log($"Spent {amount} currency. Remaining: {playerStats.currency}");
            OnCurrencyChanged?.Invoke(playerStats.currency);
            SavePlayerData();
            return true;
        }

        Debug.Log("Not enough currency!");
        return false;
    }

    public void AddPremiumCurrency(int amount)
    {
        playerStats.premiumCurrency += amount;
        Debug.Log($"Gained {amount} premium currency. Total: {playerStats.premiumCurrency}");
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        SavePlayerData();
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (playerStats.premiumCurrency >= amount)
        {
            playerStats.premiumCurrency -= amount;
            Debug.Log($"Spent {amount} premium currency. Remaining: {playerStats.premiumCurrency}");
            OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
            SavePlayerData();
            return true;
        }

        Debug.Log("Not enough premium currency!");
        return false;
    }

    // --- Shop System ---

    public bool PurchaseItem(string itemId)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null)
        {
            Debug.Log($"Item {itemId} not found in shop!");
            return false;
        }

        if (item.isPremium)
        {
            if (!SpendPremiumCurrency(item.premiumCost))
            {
                return false;
            }
        }
        else
        {
            if (!SpendCurrency(item.currentPrice))
            {
                return false;
            }
        }

        ApplyItemEffect(item);
        purchasedItems.Add(item);

        Debug.Log($"Purchased {item.itemName}!");
        OnItemPurchased?.Invoke(item);
        SavePlayerData();
        return true;
    }

    public bool CanAffordItem(string itemId)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null) return false;

        if (item.isPremium)
        {
            return playerStats.premiumCurrency >= item.premiumCost;
        }
        else
        {
            return playerStats.currency >= item.currentPrice;
        }
    }

    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case ItemType.HealthPotion:
                Heal(item.statBonus);
                break;

            case ItemType.AttackBoost:
                playerStats.baseAttack += item.statBonus;
                Debug.Log($"Attack increased to {playerStats.baseAttack}");
                break;

            case ItemType.DefenseBoost:
                playerStats.baseDefense += item.statBonus;
                Debug.Log($"Defense increased to {playerStats.baseDefense}");
                break;

            case ItemType.CritBoost:
                playerStats.criticalChance += item.statBonus;
                playerStats.criticalChance = Mathf.Clamp01(playerStats.criticalChance);
                Debug.Log($"Crit chance increased to {playerStats.criticalChance * 100}%");
                break;

            case ItemType.PremiumWeapon:
                playerStats.baseAttack += item.statBonus;
                Debug.Log($"Premium weapon equipped! Attack: {playerStats.baseAttack}");
                break;

            case ItemType.PremiumArmor:
                playerStats.baseDefense += item.statBonus;
                playerStats.maxHealth += 50f;
                playerStats.currentHealth += 50f;
                OnHealthChanged?.Invoke(playerStats.currentHealth);
                Debug.Log($"Premium armor equipped! Defense: {playerStats.baseDefense}, Max HP: {playerStats.maxHealth}");
                break;
        }
    }

    // --- Level System ---

    public void GainLevel()
    {
        playerStats.playerLevel++;
        playerStats.maxHealth += 10f;
        playerStats.currentHealth = playerStats.maxHealth;
        playerStats.baseAttack += 2f;
        playerStats.baseDefense += 1f;

        RecalculateShopPrices();

        Debug.Log($"Level up! Now level {playerStats.playerLevel}");
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    // --- IAP Handling ---

    public void OnIAPPurchaseComplete(string productId)
    {
        switch (productId)
        {
            case "com.game.gems_100":
                AddPremiumCurrency(100);
                break;
            case "com.game.gems_500":
                AddPremiumCurrency(500);
                break;
            case "com.game.gems_1200":
                AddPremiumCurrency(1200);
                break;
            case "com.game.gold_1000":
                AddCurrency(1000);
                break;
            case "com.game.gold_5000":
                AddCurrency(5000);
                break;
            case "com.game.starter_pack":
                AddPremiumCurrency(200);
                AddCurrency(2000);
                playerStats.maxHealth += 25f;
                Heal(playerStats.maxHealth);
                break;
            default:
                Debug.LogWarning($"Unknown IAP product: {productId}");
                break;
        }

        SavePlayerData();
    }

    // --- Save/Load ---

    public void SavePlayerData()
    {
        string json = JsonUtility.ToJson(playerStats);
        PlayerPrefs.SetString("PlayerStats", json);
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        if (PlayerPrefs.HasKey("PlayerStats"))
        {
            string json = PlayerPrefs.GetString("PlayerStats");
            playerStats = JsonUtility.FromJson<PlayerStats>(json);
            Debug.Log("Player data loaded.");
        }
        else
        {
            playerStats = new PlayerStats();
            Debug.Log("No save data found. Starting fresh.");
        }

        RecalculateShopPrices();
    }

    public void ResetPlayerData()
    {
        PlayerPrefs.DeleteKey("PlayerStats");
        playerStats = new PlayerStats();
        purchasedItems.Clear();
        RecalculateShopPrices();
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        OnCurrencyChanged?.Invoke(playerStats.currency);
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        Debug.Log("Player data reset.");
    }

    // --- Utility ---

    public float GetHealthPercentage()
    {
        return playerStats.currentHealth / playerStats.maxHealth;
    }

    public string GetPlayerSummary()
    {
        return $"Level: {playerStats.playerLevel}\n" +
               $"HP: {playerStats.currentHealth:F0}/{playerStats.maxHealth:F0}\n" +
               $"ATK: {playerStats.baseAttack:F1}\n" +
               $"DEF: {playerStats.baseDefense:F1}\n" +
               $"CRIT: {playerStats.criticalChance * 100:F1}%\n" +
               $"Gold: {playerStats.currency}\n" +
               $"Gems: {playerStats.premiumCurrency}";
    }
}

public class Enemy : MonoBehaviour
{
    public string enemyName = "Enemy";
    public float maxHealth = 50f;
    public float currentHealth = 50f;
    public float attackPower = 15f;
    public float defense = 3f;
    public int currencyDrop = 25;
    public int experienceValue = 10;

    public event Action<float> OnEnemyHealthChanged;
    public event Action OnEnemyDied;

    private void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage()
    {
        if (GameManager.Instance == null) return;

        float damage = GameManager.Instance.CalculateOutgoingDamage(defense);
        currentHealth -= damage;
        currentHealth = Mathf.Max(currentHealth, 0f);

        Debug.Log($"{enemyName} took {damage:F1} damage. HP: {currentHealth:F0}/{maxHealth:F0}");
        OnEnemyHealthChanged?.Invoke(currentHealth);

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    public void AttackPlayer()
    {
        if (GameManager.Instance == null) return;

        GameManager.Instance.TakeDamage(attackPower);
        Debug.Log($"{enemyName} attacked player for {attackPower} raw damage.");
    }

    private void Die()
    {
        Debug.Log($"{enemyName} has been defeated!");
        GameManager.Instance.AddCurrency(currencyDrop);
        OnEnemyDied?.Invoke();
        Destroy(gameObject, 0.5f);
    }
}

public class ShopUI : MonoBehaviour
{
    private void OnEnable()
    {
        if (GameManager.Instance != null)
        {
            GameManager.Instance.RecalculateShopPrices();
        }
    }

    public void OnPurchaseButtonClicked(string itemId)
    {
        if (GameManager.Instance == null) return;

        if (GameManager.Instance.CanAffordItem(itemId))
        {
            bool success = GameManager.Instance.PurchaseItem(itemId);
            if (success)
            {
                Debug.Log("Purchase successful!");
                RefreshUI();
            }
        }
        else
        {
            Debug.Log("Cannot afford this item!");
            ShowInsufficientFundsPrompt(itemId);
        }
    }

    private void ShowInsufficientFundsPrompt(string itemId)
    {
        ShopItem item = GameManager.Instance.shopInventory.Find(i => i.itemId == itemId);
        if (item != null && !item.isPremium)
        {
            Debug.Log("Would you like to purchase more gold?");
        }
        else if (item != null && item.isPremium)
        {
            Debug.Log("Would you like to purchase more gems?");
        }
    }

    private void RefreshUI()
    {
        Debug.Log("Refreshing shop UI...");
        Debug.Log(GameManager.Instance.GetPlayerSummary());
    }
}